import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

const Logo = () => (
  <div style={{
    width: 120, height: 90, background: 'var(--green)',
    borderRadius: 20, margin: '0 auto 32px',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    boxShadow: '0 8px 24px rgba(58,125,44,0.3)'
  }}>
    <span style={{ color: 'white', fontSize: 28, fontWeight: 800 }}>QK</span>
  </div>
);

export default function SignIn() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await api.post('/auth/login', { email, password });
      login(res.data.token, res.data.user);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container" style={{ padding: '40px 24px' }}>
      <Logo />
      <h1 style={{ textAlign: 'center', fontSize: 26, fontWeight: 800, marginBottom: 8 }}>
        QolKomek
      </h1>
      <p style={{ textAlign: 'center', color: 'var(--text-muted)', marginBottom: 32 }}>
        Найди помощь рядом с тобой
      </p>

      {error && <div className="error-msg">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="input-group">
          <label>Email</label>
          <input
            type="email"
            placeholder="example@email.com"
            value={email}
            onChange={e => setEmail(e.target.value)}
            required
          />
        </div>
        <div className="input-group">
          <label>Password</label>
          <input
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={e => setPassword(e.target.value)}
            required
          />
        </div>

        <div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
          <button type="button" className="btn-secondary" style={{ width: 'auto', flex: 1 }}>
            Google
          </button>
          <button type="button" className="btn-secondary" style={{ width: 'auto', flex: 1 }}>
            Apple
          </button>
        </div>

        <button type="submit" className="btn-primary" disabled={loading}>
          {loading ? 'Входим...' : 'Sign In'}
        </button>
      </form>

      <p style={{ textAlign: 'center', marginTop: 20, color: 'var(--text-muted)' }}>
        Нет аккаунта?{' '}
        <Link to="/register" style={{ color: 'var(--green)', fontWeight: 600 }}>
          Зарегистрироваться
        </Link>
      </p>
    </div>
  );
}
